// Seed the operator's input text into workflow.objective. Same pattern as
// goal-test-v1/Start; the Goal node's goalObjective template reads workflow.objective.
var text = (input && input.text) ? String(input.text) : '';
if (text) { setWorkflow('objective', text); }

